def generate_all_subsets(nums: list) -> list[list]:
    n = len(nums)
    power_set = []

    for i in range(1 << n):
        current_subset = []
        for j in range(n):
            if (i >> j) & 1:
                current_subset.append(nums[j])
        power_set.append(current_subset)

    return power_set
